import { useState } from 'react';
import { useCompany, useUpdateCompany, useCompanyStats } from '@/hooks/useCompany';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import {
    Building2,
    Users,
    Megaphone,
    Link2,
    FileCheck,
    Loader2,
    Save,
} from 'lucide-react';

export default function Empresa() {
    const { data: company, isLoading } = useCompany();
    const { data: stats } = useCompanyStats();
    const updateCompany = useUpdateCompany();

    const [form, setForm] = useState<{
        name: string;
    } | null>(null);

    const hasChanges = form !== null;

    const handleEdit = () => {
        if (company) {
            setForm({
                name: company.name || '',
            });
        }
    };

    const handleSave = async () => {
        if (!form) return;
        await updateCompany.mutateAsync(form);
        setForm(null);
    };

    const handleCancel = () => {
        setForm(null);
    };

    if (isLoading) {
        return (
            <div className="p-6 flex items-center justify-center min-h-[400px]">
                <Loader2 className="w-6 h-6 animate-spin text-ch-orange" />
            </div>
        );
    }

    return (
        <div className="p-6 space-y-6">
            {/* Header */}
            <div className="flex items-center justify-between">
                <div>
                    <h1 className="text-2xl font-bold text-ch-white">Empresa</h1>
                    <p className="text-ch-text-muted">
                        Configure as informações da sua empresa
                    </p>
                </div>
                {!hasChanges ? (
                    <Button onClick={handleEdit} variant="outline" className="border-ch-dark-gray">
                        Editar
                    </Button>
                ) : (
                    <div className="flex gap-2">
                        <Button onClick={handleCancel} variant="outline" className="border-ch-dark-gray">
                            Cancelar
                        </Button>
                        <Button
                            onClick={handleSave}
                            disabled={updateCompany.isPending}
                            className="bg-ch-orange hover:bg-ch-orange/90"
                        >
                            {updateCompany.isPending ? (
                                <Loader2 className="w-4 h-4 mr-2 animate-spin" />
                            ) : (
                                <Save className="w-4 h-4 mr-2" />
                            )}
                            Salvar
                        </Button>
                    </div>
                )}
            </div>

            {/* Limits Card */}
            <div className="glass rounded-xl p-6">
                <div className="flex items-center gap-4 mb-6">
                    <div className="p-3 rounded-xl bg-ch-orange/10">
                        <Building2 className="w-6 h-6 text-ch-orange" />
                    </div>
                    <div>
                        <p className="text-sm text-ch-text-muted">Plano Atual</p>
                        <p className="text-xl font-bold text-ch-orange">Plano Básico</p>
                    </div>
                </div>

                {/* Limits */}
                <div className="grid grid-cols-3 gap-6 pt-6 border-t border-white/5">
                    <div>
                        <p className="text-sm text-ch-text-dimmed">Campanhas</p>
                        <p className="text-lg font-semibold text-ch-white">
                            {stats?.totalCampaigns || 0} / {company?.max_campaigns || 10}
                        </p>
                        <div className="mt-2 h-1.5 bg-ch-dark-gray rounded-full overflow-hidden">
                            <div
                                className="h-full bg-ch-orange transition-all"
                                style={{ width: `${Math.min(100, ((stats?.totalCampaigns || 0) / (company?.max_campaigns || 10)) * 100)}%` }}
                            />
                        </div>
                    </div>
                    <div>
                        <p className="text-sm text-ch-text-dimmed">Integrações</p>
                        <p className="text-lg font-semibold text-ch-white">
                            {stats?.activeIntegrations || 0} / {company?.max_integrations || 2}
                        </p>
                        <div className="mt-2 h-1.5 bg-ch-dark-gray rounded-full overflow-hidden">
                            <div
                                className="h-full bg-blue-500 transition-all"
                                style={{ width: `${Math.min(100, ((stats?.activeIntegrations || 0) / (company?.max_integrations || 2)) * 100)}%` }}
                            />
                        </div>
                    </div>
                    <div>
                        <p className="text-sm text-ch-text-dimmed">Usuários</p>
                        <p className="text-lg font-semibold text-ch-white">
                            {stats?.totalUsers || 0} / {company?.max_users || 5}
                        </p>
                        <div className="mt-2 h-1.5 bg-ch-dark-gray rounded-full overflow-hidden">
                            <div
                                className="h-full bg-purple-500 transition-all"
                                style={{ width: `${Math.min(100, ((stats?.totalUsers || 0) / (company?.max_users || 5)) * 100)}%` }}
                            />
                        </div>
                    </div>
                </div>
            </div>

            {/* Company Info */}
            <div className="glass rounded-xl p-6 space-y-6">
                <h2 className="font-semibold text-ch-white">Informações da Empresa</h2>

                <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                    <div className="space-y-2">
                        <label className="text-sm text-ch-text-muted">Nome da Empresa</label>
                        {hasChanges ? (
                            <Input
                                value={form?.name || ''}
                                onChange={(e) => setForm(f => f && { ...f, name: e.target.value })}
                                className="bg-ch-dark-gray border-ch-dark-gray"
                            />
                        ) : (
                            <p className="text-ch-white font-medium">{company?.name || '-'}</p>
                        )}
                    </div>

                    <div className="space-y-2">
                        <label className="text-sm text-ch-text-muted">Slug</label>
                        <p className="text-ch-white">{company?.slug || '-'}</p>
                    </div>
                </div>
            </div>

            {/* Stats */}
            <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
                <div className="glass rounded-xl p-5">
                    <div className="flex items-center gap-3">
                        <div className="p-2 bg-ch-orange/10 rounded-lg">
                            <Megaphone className="w-5 h-5 text-ch-orange" />
                        </div>
                        <div>
                            <p className="text-2xl font-bold text-ch-white">{stats?.totalCampaigns || 0}</p>
                            <p className="text-sm text-ch-text-muted">Campanhas</p>
                        </div>
                    </div>
                </div>
                <div className="glass rounded-xl p-5">
                    <div className="flex items-center gap-3">
                        <div className="p-2 bg-blue-500/10 rounded-lg">
                            <Link2 className="w-5 h-5 text-blue-500" />
                        </div>
                        <div>
                            <p className="text-2xl font-bold text-ch-white">{stats?.activeIntegrations || 0}</p>
                            <p className="text-sm text-ch-text-muted">Integrações</p>
                        </div>
                    </div>
                </div>
                <div className="glass rounded-xl p-5">
                    <div className="flex items-center gap-3">
                        <div className="p-2 bg-purple-500/10 rounded-lg">
                            <Users className="w-5 h-5 text-purple-500" />
                        </div>
                        <div>
                            <p className="text-2xl font-bold text-ch-white">{stats?.totalUsers || 0}</p>
                            <p className="text-sm text-ch-text-muted">Usuários</p>
                        </div>
                    </div>
                </div>
                <div className="glass rounded-xl p-5">
                    <div className="flex items-center gap-3">
                        <div className="p-2 bg-green-500/10 rounded-lg">
                            <FileCheck className="w-5 h-5 text-green-500" />
                        </div>
                        <div>
                            <p className="text-2xl font-bold text-ch-white">{stats?.totalAudits || 0}</p>
                            <p className="text-sm text-ch-text-muted">Auditorias</p>
                        </div>
                    </div>
                </div>
            </div>
        </div>
    );
}

import { useState } from 'react';
import { motion } from 'framer-motion';
import { Tabs, TabsContent, TabsList, TabsTrigger } from '@/components/ui/tabs';
import { Button } from '@/components/ui/button';
import {
    RefreshCw,
    BarChart3,
    Loader2,
    Sparkles,
    AlertTriangle,
    Lightbulb,
    Users,
    MapPin
} from 'lucide-react';
import { toast } from 'sonner';
import { supabase } from '@/integrations/supabase/client';
import { useAuth } from '@/contexts/AuthContext';
import GoogleAdsPerformance from '@/components/google-ads/GoogleAdsPerformance';
import GoogleAdsAudit from '@/components/google-ads/GoogleAdsAudit';
import GoogleAdsInsights from '@/components/google-ads/GoogleAdsInsights';
import GoogleAdsAICreatives from '@/components/google-ads/GoogleAdsCreatives';
import GoogleAdsGeo from '@/components/google-ads/GoogleAdsGeo';

const container = {
    hidden: { opacity: 0 },
    show: {
        opacity: 1,
        transition: { staggerChildren: 0.05 }
    }
};

const item = {
    hidden: { y: 20, opacity: 0 },
    show: { y: 0, opacity: 1 }
};

export default function GoogleAdsPage() {
    const { session } = useAuth();
    const [isSyncing, setIsSyncing] = useState(false);

    const handleSync = async () => {
        setIsSyncing(true);
        try {
            // Fetch user company_id
            const { data: { user } } = await supabase.auth.getUser();
            if (!user) return;

            // Ideally we get company_id from a hook context, assuming single tenant for now or grabbing from DB
            const { data: profile } = await supabase
                .from('users')
                .select('company_id')
                .eq('id', user.id)
                .single();

            if (!profile?.company_id) {
                toast.error("Empresa não encontrada para este usuário.");
                return;
            }

            const { error } = await supabase.functions.invoke('sync-google-stub', {
                body: { company_id: profile.company_id }
            });

            if (error) throw error;
            toast.success("Dados do Google Ads sincronizados!");
            window.location.reload(); // Simple refresh to pick up new data
        } catch (error) {
            console.error(error);
            toast.error("Erro ao sincronizar dados.");
        } finally {
            setIsSyncing(false);
        }
    };

    return (
        <motion.div
            initial="hidden"
            animate="show"
            variants={container}
            className="p-6 space-y-8"
        >
            <motion.div variants={item} className="flex flex-col md:flex-row md:items-center justify-between gap-6">
                <div>
                    <div className="flex items-center gap-3 mb-1">
                        <Users className="w-4 h-4 text-[#4285F4]" />
                        <span className="text-[10px] font-black text-[#4285F4] uppercase tracking-wide">Google Ads Intelligence</span>
                    </div>
                    <h1 className="text-3xl font-black text-ch-white tracking-tight uppercase">Performance & Compliance</h1>
                    <p className="text-ch-text-muted font-medium mt-1">Gestão avançada de search, proteção de marca e leilão.</p>
                </div>
                {/* Botão de Sincronização removido conforme solicitação para focar apenas na visualização */}
            </motion.div>

            <Tabs defaultValue="performance" className="space-y-6">
                <TabsList className="bg-white/5 border border-white/10 p-1 rounded-xl flex flex-wrap md:flex-nowrap gap-2 md:gap-0">
                    <TabsTrigger
                        value="performance"
                        className="data-[state=active]:bg-ch-orange data-[state=active]:text-black h-10 px-6 rounded-lg text-ch-text-dimmed uppercase font-black text-[10px] tracking-widest transition-all flex-1 md:flex-none"
                    >
                        <BarChart3 className="w-3.5 h-3.5 mr-2" />
                        Performance
                    </TabsTrigger>

                    <TabsTrigger
                        value="geo"
                        className="data-[state=active]:bg-blue-500 data-[state=active]:text-white h-10 px-6 rounded-lg text-ch-text-dimmed uppercase font-black text-[10px] tracking-widest transition-all flex-1 md:flex-none"
                    >
                        <MapPin className="w-3.5 h-3.5 mr-2" />
                        Unidades e Localidades
                    </TabsTrigger>

                    <TabsTrigger
                        value="ai-creatives"
                        className="data-[state=active]:bg-purple-500 data-[state=active]:text-white h-10 px-6 rounded-lg text-ch-text-dimmed uppercase font-black text-[10px] tracking-widest transition-all flex-1 md:flex-none"
                    >
                        <Sparkles className="w-3.5 h-3.5 mr-2" />
                        Análise de IA
                    </TabsTrigger>

                    <TabsTrigger
                        value="audit"
                        className="data-[state=active]:bg-ch-orange data-[state=active]:text-black h-10 px-6 rounded-lg text-ch-text-dimmed uppercase font-black text-[10px] tracking-widest transition-all flex-1 md:flex-none"
                    >
                        <AlertTriangle className="w-3.5 h-3.5 mr-2" />
                        Auditoria
                    </TabsTrigger>
                    <TabsTrigger
                        value="insights"
                        className="data-[state=active]:bg-ch-orange data-[state=active]:text-black h-10 px-6 rounded-lg text-ch-text-dimmed uppercase font-black text-[10px] tracking-widest transition-all flex-1 md:flex-none"
                    >
                        <Lightbulb className="w-3.5 h-3.5 mr-2" />
                        Insights do Leilão
                    </TabsTrigger>
                </TabsList>

                <TabsContent value="performance" className="animate-in fade-in-50 slide-in-from-bottom-2 duration-500">
                    <GoogleAdsPerformance />
                </TabsContent>

                <TabsContent value="geo" className="animate-in fade-in-50 slide-in-from-bottom-2 duration-500">
                    <GoogleAdsGeo />
                </TabsContent>

                <TabsContent value="ai-creatives" className="animate-in fade-in-50 slide-in-from-bottom-2 duration-500">
                    <GoogleAdsAICreatives />
                </TabsContent>

                <TabsContent value="audit" className="animate-in fade-in-50 slide-in-from-bottom-2 duration-500">
                    <GoogleAdsAudit />
                </TabsContent>

                <TabsContent value="insights" className="animate-in fade-in-50 slide-in-from-bottom-2 duration-500">
                    <GoogleAdsInsights />
                </TabsContent>
            </Tabs>
        </motion.div>
    );
}

