import { useEffect, useState } from 'react';
import { useAuth } from '@/contexts/AuthContext';
import { supabase, supabaseUrl } from '@/integrations/supabase/client';
import { useToast } from '@/hooks/use-toast';
import { Button } from '@/components/ui/button';
import {
    Facebook,
    RefreshCw,
    Check,
    XCircle,
    AlertTriangle,
    Loader2,
    Link2,
    Unlink,
    Globe,
    ExternalLink,
    ShieldCheck,
    Zap
} from 'lucide-react';
import { format } from 'date-fns';
import { ptBR } from 'date-fns/locale';
import { motion, AnimatePresence } from 'framer-motion';

interface Integration {
    id: string;
    company_id: string;
    platform: string;
    account_id: string;
    account_name: string;
    status: string;
    last_sync_at: string | null;
    token_expires_at: string | null;
    created_at: string;
}

const container = {
    hidden: { opacity: 0 },
    show: {
        opacity: 1,
        transition: {
            staggerChildren: 0.1
        }
    }
};

const item = {
    hidden: { opacity: 0, y: 20 },
    show: { opacity: 1, y: 0 }
};

export default function Integracoes() {
    const { user } = useAuth();
    const { toast } = useToast();
    const [integrations, setIntegrations] = useState<Integration[]>([]);
    const [loading, setLoading] = useState(true);
    const [syncing, setSyncing] = useState<string | null>(null);
    const [connecting, setConnecting] = useState(false);

    useEffect(() => {
        fetchIntegrations();

        const params = new URLSearchParams(window.location.search);
        if (params.get('success') === 'true') {
            const accounts = params.get('accounts');
            toast({
                title: 'Conexão realizada!',
                description: `${accounts} conta(s) de anúncios conectada(s) com sucesso.`,
            });
            window.history.replaceState({}, '', '/integracoes');
            fetchIntegrations();
        }
    }, []);

    const fetchIntegrations = async () => {
        if (!user?.company?.id) return;

        setLoading(true);
        try {
            const { data, error } = await supabase
                .from('integrations')
                .select('*')
                .eq('company_id', user.company.id)
                .order('created_at', { ascending: false });

            if (error) throw error;
            setIntegrations(data || []);
        } catch (error) {
            console.error('Error fetching integrations:', error);
            toast({
                title: 'Erro',
                description: 'Não foi possível carregar as integrações.',
                variant: 'destructive',
            });
        } finally {
            setLoading(false);
        }
    };

    const handleConnectMeta = () => {
        if (!user?.company?.id || !user?.id) {
            toast({
                title: 'Erro',
                description: 'Dados do usuário não encontrados.',
                variant: 'destructive',
            });
            return;
        }

        setConnecting(true);
        const META_APP_ID = import.meta.env.VITE_META_APP_ID;
        const SUPABASE_URL = supabaseUrl;

        if (!META_APP_ID) {
            toast({
                title: 'Erro de configuração',
                description: 'META_APP_ID não configurado.',
                variant: 'destructive',
            });
            setConnecting(false);
            return;
        }

        const state = btoa(JSON.stringify({
            user_id: user.id,
            company_id: user.company.id,
            redirect_url: window.location.origin + '/integracoes'
        }));

        const redirectUri = `${SUPABASE_URL}/functions/v1/meta-oauth-callback`;
        const scopes = 'ads_read,ads_management,business_management,pages_read_engagement,read_insights';
        const oauthUrl = `https://www.facebook.com/v19.0/dialog/oauth?client_id=${META_APP_ID}&redirect_uri=${encodeURIComponent(redirectUri)}&scope=${scopes}&state=${state}&response_type=code`;
        window.location.href = oauthUrl;
    };

    const handleSync = async (integrationId: string) => {
        setSyncing(integrationId);
        try {
            const { data, error } = await supabase.functions.invoke('sync-meta-data', {
                body: { integration_id: integrationId, sync_type: 'full' }
            });

            if (error) throw error;

            toast({
                title: 'Sincronização concluída',
                description: `${data.results?.[0]?.items_synced || 0} itens sincronizados.`,
            });

            fetchIntegrations();
        } catch (error) {
            console.error('Sync error:', error);
            toast({
                title: 'Erro na sincronização',
                description: 'Não foi possível sincronizar os dados.',
                variant: 'destructive',
            });
        } finally {
            setSyncing(null);
        }
    };

    const handleDisconnect = async (integrationId: string) => {
        if (!confirm('Tem certeza que deseja desconectar esta conta?')) return;

        try {
            const { error } = await supabase
                .from('integrations')
                .update({ status: 'disconnected' })
                .eq('id', integrationId);

            if (error) throw error;

            toast({
                title: 'Conta desconectada',
                description: 'A integração foi removida com sucesso.',
            });

            fetchIntegrations();
        } catch (error) {
            console.error('Disconnect error:', error);
            toast({
                title: 'Erro',
                description: 'Não foi possível desconectar a conta.',
                variant: 'destructive',
            });
        }
    };

    const getStatusBadge = (integration: Integration) => {
        const isExpired = integration.token_expires_at &&
            new Date(integration.token_expires_at) < new Date();

        if (isExpired) {
            return (
                <span className="flex items-center gap-1.5 text-[10px] font-black uppercase tracking-widest px-3 py-1.5 rounded-full bg-amber-500/10 text-amber-500 border border-amber-500/20">
                    <AlertTriangle className="w-3.5 h-3.5" />
                    Token expirado
                </span>
            );
        }

        if (integration.status === 'active') {
            return (
                <span className="flex items-center gap-1.5 text-[10px] font-black uppercase tracking-widest px-3 py-1.5 rounded-full bg-emerald-500/10 text-emerald-500 border border-emerald-500/20">
                    <Check className="w-3.5 h-3.5" />
                    Ativo
                </span>
            );
        }

        return (
            <span className="flex items-center gap-1.5 text-[10px] font-black uppercase tracking-widest px-3 py-1.5 rounded-full bg-rose-500/10 text-rose-500 border border-rose-500/20">
                <XCircle className="w-3.5 h-3.5" />
                Inativo
            </span>
        );
    };

    const metaIntegrations = integrations.filter(i => i.platform === 'meta' && i.status !== 'disconnected');

    return (
        <motion.div
            initial="hidden"
            animate="show"
            variants={container}
            className="p-6 space-y-8"
        >
            {/* Header */}
            <motion.div variants={item} className="flex flex-col md:flex-row md:items-center justify-between gap-6">
                <div>
                    <div className="flex items-center gap-2 mb-1">
                        <Globe className="w-5 h-5 text-ch-orange animate-pulse" />
                        <span className="text-xs font-black text-ch-orange uppercase tracking-[0.2em]">Centro de Conexões</span>
                    </div>
                    <h1 className="text-4xl font-black text-ch-white tracking-tight italic uppercase">Integrações</h1>
                    <p className="text-ch-text-dimmed font-medium mt-1">
                        Conecte seu ecossistema de anúncios para ativar a inteligência <span className="text-ch-white font-bold">Click.Hero</span>
                    </p>
                </div>
                <div className="flex items-center gap-3">
                    <div className="flex items-center gap-2 px-4 py-2 bg-emerald-500/5 border border-emerald-500/10 rounded-xl">
                        <ShieldCheck className="w-4 h-4 text-emerald-500" />
                        <span className="text-[10px] font-black text-emerald-500 uppercase tracking-widest">Ambiente Seguro</span>
                    </div>
                </div>
            </motion.div>

            {/* Platform Connect Grid */}
            <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
